import ldap

def search_user_by_username(ldap_server, base_dn, username):
    try:
        # Initialize the LDAP connection
        ldap_conn = ldap.initialize(ldap_server)
        
        # Set LDAP version to 3 (required for SASL and other modern features)
        ldap_conn.set_option(ldap.OPT_PROTOCOL_VERSION, 3)
        
        # Perform a simple search with filter
        search_filter = f"(uid={username})"
        result = ldap_conn.search_s(base_dn, ldap.SCOPE_SUBTREE, search_filter)
        
        # Return the results
        return result
    
    except ldap.LDAPError as e:
        print(f"LDAP error: {e}")
        return None

